import pytest

# The function to test
def deep_get(d: dict, keys: str, default=None):
    """Get nested dict value by dot-separated keys."""
    for key in keys.split('.'):
        if isinstance(d, dict):
            d = d.get(key, default)
        else:
            return default
    return d

# --- Tests ---

def test_deep_get_happy_path():
    """Test retrieving values from existing nested structures."""
    data = {
        "a": 1,
        "b": {
            "c": 2,
            "d": {
                "e": "hello"
            }
        }
    }
    assert deep_get(data, "a") == 1
    assert deep_get(data, "b.c") == 2
    assert deep_get(data, "b.d.e") == "hello"

def test_deep_get_default_value():
    """Test returning the default value when a key is missing."""
    data = {"a": {"b": 1}}

    # Key doesn't exist at top level
    assert deep_get(data, "z") is None
    # Key doesn't exist in nested level
    assert deep_get(data, "a.c") is None
    # Custom default value
    assert deep_get(data, "a.c", default="missing") == "missing"
    assert deep_get(data, "x.y.z", default=0) == 0

def test_deep_get_non_dict_traversal():
    """Test behavior when the path attempts to traverse into a non-dict object."""
    data = {
        "a": 1,
        "b": {"c": "not_a_dict"}
    }
    # Attempting to access 'b.c.d' where 'b.c' is a string
    assert deep_get(data, "b.c.d") is None
    assert deep_get(data, "b.c.d", default="fallback") == "fallback"
    # Attempting to access 'a.b' where 'a' is an int
    assert deep_get(data, "a.b") is None

def test_deep_get_edge_cases():
    """Test edge cases like empty strings or empty dicts."""
    data = {"a": 1}

    # Empty dictionary
    assert deep_get({}, "a.b.c") is None

    # Empty key string (split('.') on "" returns [''])
    # This checks if the function handles an empty string key gracefully
    assert deep_get(data, "") is None

    # Single key that is an empty string
    data_with_empty_key = {"": "empty"}
    assert deep_get(data_with_empty_key, "") == "empty"

def test_deep_get_with_falsy_values():
    """Ensure the function doesn't confuse falsy values (0, False, None) with missing keys."""
    data = {
        "a": 0,
        "b": False,
        "c": None,
        "d": {"e": []}
    }
    assert deep_get(data, "a") == 0
    assert deep_get(data, "b") is False
    assert deep_get(data, "c") is None
    assert deep_get(data, "d.e") == []

    # Verify that if the value IS None, it doesn't trigger the default unless the key is missing
    # Note: In the current implementation, if d.get(key) returns None, 
    # it is treated as the value, not as a trigger for the default.
    assert deep_get(data, "c", default="missing") is None

